SELECT * FROM surgery_record
WHERE deleted = 0

    AND patient_name LIKE CONCAT('%', #{patientName}, '%')


    AND hospital_no = #{hospitalNo}


    AND process_status = #{status}


    AND DATE(upload_time) >= #{startDate}


    AND DATE(upload_time) <= #{endDate}

ORDER BY upload_time DESC
LIMIT #{offset}, #{limit}

SELECT COUNT(*) FROM surgery_record
WHERE deleted = 0

    AND patient_name LIKE CONCAT('%', #{patientName}, '%')


    AND hospital_no = #{hospitalNo}


    AND process_status = #{status}


    AND DATE(upload_time) >= #{startDate}


    AND DATE(upload_time) <= #{endDate}

mapper.update:
UPDATE surgery_record SET process_status = #{status},
process_message = #{message},
updated_time = NOW() WHERE id = #{id}

mapper.select:
SELECT id, department, upload_user_id, original_file_name, template_id, upload_time, process_status FROM surgery_record WHERE deleted = 0 AND upload_time >= #{fromTime} AND process_status IN ('NER_DONE', 'COMPLETED') AND template_id IS NOT NULL
AND department = #{department}
ORDER BY upload_time DESC LIMIT 500

SELECT COUNT(*) AS totalRecords, SUM(CASE WHEN process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) AS extractedRecords, COUNT(DISTINCT department) AS totalDepartments, COUNT(DISTINCT upload_user_id) AS totalSurgeons, SUM(CASE WHEN manual_duration_est IS NOT NULL AND manual_duration_est > 0 THEN manual_duration_est ELSE 0 END) AS totalManualDuration, SUM(CASE WHEN fill_duration IS NOT NULL THEN fill_duration ELSE 0 END) AS totalActualDuration FROM surgery_record WHERE deleted = 0
AND DATE(upload_time) >= #{startDate}
AND DATE(upload_time) <= #{endDate}
AND department = #{department}

SELECT DATE(upload_time) AS date,
department NULL AS department, COUNT(*) AS totalRecords, SUM(CASE WHEN process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) AS extractedRecords, ROUND( SUM(CASE WHEN process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS coverageRate FROM surgery_record WHERE deleted = 0
AND DATE(upload_time) >= #{startDate}
AND DATE(upload_time) <= #{endDate}
AND department = #{department}
GROUP BY DATE(upload_time)
, department
ORDER BY date

SELECT DATE(r.upload_time) AS date, r.department AS department, COALESCE(h.chief_surgeon, h.surgeon, r.upload_user_name) AS surgeon, COUNT(*) AS recordCount, AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE NULL END) AS avgManualDuration, AVG(CASE WHEN h.fill_duration IS NOT NULL THEN h.fill_duration ELSE NULL END) AS avgActualDuration, ROUND( (AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE 0 END) - AVG(CASE WHEN h.fill_duration IS NOT NULL THEN h.fill_duration ELSE 0 END)) * 100.0 / NULLIF(AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE NULL END), 0), 2 ) AS timeSavedRate FROM surgery_record r LEFT JOIN medical_record_home h ON h.record_id = r.id AND h.deleted = 0 WHERE r.deleted = 0 AND h.fill_duration IS NOT NULL
AND DATE(r.upload_time) >= #{startDate}
AND DATE(r.upload_time) <= #{endDate}
AND r.department = #{department}
AND (h.chief_surgeon = #{surgeon} OR h.surgeon = #{surgeon})
GROUP BY DATE(r.upload_time)
, r.department
, COALESCE(h.chief_surgeon, h.surgeon, r.upload_user_name)
HAVING avgManualDuration IS NOT NULL ORDER BY date

SELECT r.department AS department, COUNT(*) AS totalRecords, SUM(CASE WHEN r.process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) AS extractedRecords, ROUND( SUM(CASE WHEN r.process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS coverageRate, ROUND( (AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE 0 END) - AVG(CASE WHEN h.fill_duration IS NOT NULL THEN h.fill_duration ELSE 0 END)) * 100.0 / NULLIF(AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE NULL END), 0), 2 ) AS avgTimeSavedRate FROM surgery_record r LEFT JOIN medical_record_home h ON h.record_id = r.id AND h.deleted = 0 WHERE r.deleted = 0 AND r.department IS NOT NULL
AND DATE(r.upload_time) >= #{startDate}
AND DATE(r.upload_time) <= #{endDate}
GROUP BY r.department ORDER BY totalRecords DESC

SELECT COALESCE(h.chief_surgeon, h.surgeon, r.upload_user_name) AS surgeon, COUNT(*) AS recordCount, ROUND( (AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE 0 END) - AVG(CASE WHEN h.fill_duration IS NOT NULL THEN h.fill_duration ELSE 0 END)) * 100.0 / NULLIF(AVG(CASE WHEN h.manual_duration_est IS NOT NULL AND h.manual_duration_est > 0 THEN h.manual_duration_est ELSE NULL END), 0), 2 ) AS avgTimeSavedRate, ROUND( SUM(CASE WHEN r.process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS coverageRate FROM surgery_record r LEFT JOIN medical_record_home h ON h.record_id = r.id AND h.deleted = 0 WHERE r.deleted = 0 AND COALESCE(h.chief_surgeon, h.surgeon, r.upload_user_name) IS NOT NULL
AND DATE(r.upload_time) >= #{startDate}
AND DATE(r.upload_time) <= #{endDate}
AND r.department = #{department}
GROUP BY COALESCE(h.chief_surgeon, h.surgeon, r.upload_user_name) HAVING recordCount >= 1 ORDER BY recordCount DESC
LIMIT #{limit}

SELECT h.surgery_name AS surgeryName, COUNT(*) AS recordCount, ROUND( SUM(CASE WHEN r.process_status IN ('NER_DONE', 'COMPLETED') THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS coverageRate FROM surgery_record r LEFT JOIN medical_record_home h ON h.record_id = r.id AND h.deleted = 0 WHERE r.deleted = 0 AND h.surgery_name IS NOT NULL AND h.surgery_name != ''
AND DATE(r.upload_time) >= #{startDate}
AND DATE(r.upload_time) <= #{endDate}
AND r.department = #{department}
GROUP BY h.surgery_name ORDER BY recordCount DESC
LIMIT #{limit}

SELECT
    h.surgery_name AS name,
    COUNT(*) AS value
FROM surgery_record r
LEFT JOIN medical_record_home h ON h.record_id = r.id AND h.deleted = 0
WHERE r.deleted = 0
  AND h.surgery_name IS NOT NULL AND h.surgery_name != ''

    AND DATE(r.upload_time) >= #{startDate}


    AND DATE(r.upload_time) <= #{endDate}


    AND r.department = #{department}

GROUP BY h.surgery_name
ORDER BY value DESC

    LIMIT #{limit}
